/* ─── HELPERS ─── */
function computeInvoiceTotals(items) {
  const subtotal = items.reduce((s, it) => s + (Number(it.amount) || 0), 0);
  const vatAmount = Math.round(subtotal * 0.21);
  const total = subtotal + vatAmount;
  return { subtotal, vat_amount: vatAmount, total };
}
function nextInvoiceNumber(invoices) {
  const year = new Date().getFullYear();
  const nums = invoices
    .map(i => { const m = (i.invoice_number || "").match(/(\d+)$/); return m ? parseInt(m[1]) : 0; })
    .filter(n => n > 0);
  const next = (nums.length > 0 ? Math.max(...nums) : 0) + 1;
  return `FA ${year}/${String(next).padStart(3, "0")}`;
}
function invoiceStatus(inv) {
  if (inv.status === "dph_odvedeno") return "dph_odvedeno";
  if (inv.status === "uhrazena") return "uhrazena";
  if (inv.status === "pripravena") return "pripravena";
  if (inv.due_date && new Date(inv.due_date) < new Date()) return "po_splatnosti";
  if (inv.status === "vystavena") return "vystavena";
  return "pripravena";
}

function StatusBadge({ inv }) {
  const s = invoiceStatus(inv);
  const map = {
    uhrazena:     { cls: "b-ok",   label: "Uhrazena ✓" },
    po_splatnosti:{ cls: "b-late", label: "Po splatnosti" },
    vystavena:    { cls: "b-vy",   label: "Vystavena" },
    pripravena:   { cls: "b-prep", label: "Připravena" },
  };
  const { cls, label } = map[s] || map.pripravena;
  return <span className={`badge ${cls}`}>{label}</span>;
}

/* ─── INVOICE ISSUE MODAL ─── */
function nextDueDate() {
  const now = new Date();
  const next = new Date(now.getFullYear(), now.getMonth() + 1, 15);
  return next.toISOString().slice(0, 10);
}

function InvoiceIssueModal({ clientId, entries, clients, invoices, onConfirm, onCancel, saving }) {
  const client = clients.find(c => c.id === clientId);
  const [selected, setSelected] = useState(() => new Set(entries.map(e => e.id)));
  const [invoiceNo, setInvoiceNo] = useState(() => nextInvoiceNumber(invoices));
  const [issueDate, setIssueDate] = useState(() => today());
  const [dueDate, setDueDate] = useState(() => nextDueDate());
  const [varSymbol, setVarSymbol] = useState(() => {
    const next = nextInvoiceNumber(invoices);
    return next.replace(/[^0-9]/g, "").slice(-6) || String(new Date().getFullYear()).slice(2) + String(invoices.length + 1).padStart(3, "0");
  });
  const [showPreview, setShowPreview] = useState(false);

  const selEntries = entries.filter(e => selected.has(e.id));
  const workAmt = selEntries.reduce((s, e) => s + (e.amount || 0), 0);
  const notary = selEntries.reduce((s, e) => s + (e.notary_fee || 0), 0);
  const admin = selEntries.reduce((s, e) => s + (e.admin_fee || 0), 0);
  const vat = Math.round(workAmt * 0.21);
  const total = workAmt + vat + notary + admin;

  const toggle = (id) => setSelected(p => { const n = new Set(p); n.has(id) ? n.delete(id) : n.add(id); return n; });

  const invoice = {
    id: uid(), invoice_number: invoiceNo,
    client_id: clientId, issue_date: issueDate, due_date: dueDate,
    items: [
      ...selEntries.filter(e => e.hours > 0).map(e => ({ id: uid(), description: e.description, hours: e.hours, rate: e.rate, amount: e.amount, no_vat: false })),
      ...(notary > 0 ? [{ id: uid(), description: "Přefakturace — notář", hours: 0, rate: 0, amount: notary, no_vat: true }] : []),
      ...(admin > 0 ? [{ id: uid(), description: "Správní poplatek — přefakturace", hours: 0, rate: 0, amount: admin, no_vat: true }] : []),
    ],
    subtotal: workAmt, vat_rate: 21, vat_amount: vat, total,
    status: "pripravena", notes: varSymbol,
    var_symbol: varSymbol,
  };

  if (showPreview) {
    return <InvoicePrintPreview invoice={invoice} client={client} workEntries={selEntries}
      onBack={() => setShowPreview(false)}
      onIssue={(sent) => onConfirm({ ...invoice, status: sent ? "vystavena" : "pripravena" }, selEntries.map(e => e.id))}
      saving={saving} />;
  }

  return (
    <div className="ov" onClick={onCancel}>
      <div style={{ background: "#fff", borderRadius: 16, padding: 28, maxWidth: 620, width: "100%", maxHeight: "90vh", overflowY: "auto", boxShadow: "0 24px 64px rgba(0,0,0,.18)" }}
        onClick={e => e.stopPropagation()}>
        <div style={{ fontFamily: "Fraunces, serif", fontSize: 20, fontWeight: 300, color: "var(--txt)", marginBottom: 4 }}>Vystavit fakturu</div>
        <div style={{ fontSize: 12.5, color: "var(--mut)", marginBottom: 20 }}>{client?.name}</div>

        {/* Entry selection */}
        <div style={{ fontSize: 9.5, letterSpacing: ".12em", textTransform: "uppercase", color: "var(--mut)", fontWeight: 500, marginBottom: 10 }}>Výkazy k fakturaci</div>
        <div style={{ border: "1px solid var(--line)", borderRadius: 10, overflow: "hidden", marginBottom: 20 }}>
          {entries.sort((a,b)=>(a.entry_date||"").localeCompare(b.entry_date||"")).map(e => (
            <label key={e.id} style={{ display: "flex", alignItems: "flex-start", gap: 12, padding: "11px 14px", borderBottom: "1px solid var(--line)", cursor: "pointer", background: selected.has(e.id) ? "#F7F5FF" : "#fff", transition: ".1s" }}>
              <input type="checkbox" checked={selected.has(e.id)} onChange={() => toggle(e.id)} style={{ marginTop: 2, accentColor: "var(--ink)", flexShrink: 0 }} />
              <div style={{ flex: 1, minWidth: 0 }}>
                <div style={{ fontSize: 12.5, color: "var(--txt)", fontWeight: 500 }}>{fmtDate(e.entry_date)} — {e.description?.slice(0, 80)}</div>
                <div style={{ fontSize: 11, color: "var(--mut)", marginTop: 2 }}>
                  {e.hours > 0 && `${e.hours} h × ${fmtKc(e.rate)}`}
                  {e.notary_fee > 0 && ` · notář ${fmtKc(e.notary_fee)}`}
                  {e.admin_fee > 0 && ` · sp.pop. ${fmtKc(e.admin_fee)}`}
                </div>
              </div>
              <div style={{ fontSize: 12.5, fontFamily: "Fraunces, serif", fontWeight: 300, color: "var(--ink)", flexShrink: 0 }}>
                {fmtKc((e.amount||0)+(e.notary_fee||0)+(e.admin_fee||0))}
              </div>
            </label>
          ))}
        </div>

        {/* Invoice settings */}
        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr 1fr", gap: 12, marginBottom: 20 }}>
          <div className="frow" style={{ marginBottom: 0 }}>
            <label>Číslo faktury</label>
            <input value={invoiceNo} onChange={e => setInvoiceNo(e.target.value)} />
          </div>
          <div className="frow" style={{ marginBottom: 0 }}>
            <label>Datum vystavení</label>
            <input type="date" value={issueDate} onChange={e => setIssueDate(e.target.value)} />
          </div>
          <div className="frow" style={{ marginBottom: 0 }}>
            <label>Splatnost</label>
            <input type="date" value={dueDate} onChange={e => setDueDate(e.target.value)} />
          </div>
        </div>
        <div className="frow" style={{ marginBottom: 20 }}>
          <label>Variabilní symbol</label>
          <input value={varSymbol} onChange={e => setVarSymbol(e.target.value)} placeholder="202642" />
        </div>

        {/* Totals */}
        <div style={{ background: "#F7F5FF", border: "1px solid var(--line)", borderRadius: 10, padding: "14px 18px", marginBottom: 20 }}>
          <div style={{ display: "flex", justifyContent: "space-between", fontSize: 13, color: "var(--mut)", marginBottom: 4 }}>
            <span>Základ daně (bez DPH)</span><span>{fmtKc(workAmt)}</span>
          </div>
          {(notary + admin) > 0 && <div style={{ display: "flex", justifyContent: "space-between", fontSize: 13, color: "var(--mut)", marginBottom: 4 }}>
            <span>Přefakturace (bez DPH)</span><span>{fmtKc(notary + admin)}</span>
          </div>}
          <div style={{ display: "flex", justifyContent: "space-between", fontSize: 13, color: "var(--mut)", marginBottom: 8 }}>
            <span>DPH 21 %</span><span>{fmtKc(vat)}</span>
          </div>
          <div style={{ display: "flex", justifyContent: "space-between", fontSize: 17, fontFamily: "Fraunces, serif", fontWeight: 300, color: "var(--ink)", borderTop: "1px solid var(--line2)", paddingTop: 10 }}>
            <span>Celkem k úhradě</span><span>{fmtKc(total)}</span>
          </div>
        </div>

        <div style={{ display: "flex", gap: 10, justifyContent: "flex-end" }}>
          <button className="btn gho" onClick={onCancel}>Zrušit</button>
          <button className="btn" onClick={() => setShowPreview(true)} disabled={selected.size === 0}>
            Náhled faktury →
          </button>
        </div>
      </div>
    </div>
  );
}

